```powershell
# Détecter les tentatives de brute force — EventID 4625
$fails = Get-WinEvent -FilterHashtable @{
    LogName   = 'Security'
    Id        = 4625
    StartTime = (Get-Date).AddHours(-24)
} -ErrorAction SilentlyContinue

if ($fails) {
    Write-Host "Échecs de connexion (24h) : $($fails.Count)"

    # Extraire les IPs et compter
    $parIP = $fails | ForEach-Object {
        if ($_.Message -match 'Source Network Address:\s+(\S+)') {
            $Matches[1]
        }
    } | Where-Object { $_ -and $_ -ne '-' } |
      Group-Object | Sort-Object Count -Descending

    Write-Host "`nTop IPs (tentatives échouées) :"
    $parIP | Select-Object -First 10 | ForEach-Object {
        $flag = if ($_.Count -ge 10) { ' [BRUTE FORCE]' } else { '' }
        Write-Host "  $($_.Name) : $($_.Count)$flag"
    }
} else {
    Write-Host "Aucun échec de connexion dans les 24 dernières heures"
}
```

```powershell
# Détecter créations de comptes et modifications de groupes sensibles
$debut = (Get-Date).AddDays(-7)

# Comptes créés
$comptesCreés = Get-WinEvent -FilterHashtable @{
    LogName   = 'Security'
    Id        = 4720
    StartTime = $debut
} -ErrorAction SilentlyContinue

Write-Host "Comptes créés (7j) : $($comptesCreés.Count)"
$comptesCreés | ForEach-Object {
    if ($_.Message -match 'Account Name:\s+(\S+)\s') {
        Write-Host "  + $($Matches[1]) — $($_.TimeCreated.ToString('yyyy-MM-dd HH:mm'))"
    }
}

# Ajouts aux groupes Administrateurs (4732)
$ajoutsAdmin = Get-WinEvent -FilterHashtable @{
    LogName   = 'Security'
    Id        = 4732
    StartTime = $debut
} -ErrorAction SilentlyContinue

Write-Host "`nAjouts groupe Admin (7j) : $($ajoutsAdmin.Count)"
if ($ajoutsAdmin) {
    $ajoutsAdmin | ForEach-Object {
        Write-Host "  [ALERTE] $($_.TimeCreated) — $($_.Message.Substring(0,[Math]::Min(200,$_.Message.Length)))"
    }
}

# Logs d'audit effacés (1102) — très suspect
$logsEffaces = Get-WinEvent -FilterHashtable @{
    LogName   = 'Security'
    Id        = 1102
    StartTime = $debut
} -ErrorAction SilentlyContinue

if ($logsEffaces) {
    Write-Host "`n[CRITIQUE] Logs d'audit effacés : $($logsEffaces.Count) fois !"
}
```

```powershell
# Nécessite : Audit Process Creation activé dans la GPO
# Computer Config > Windows Settings > Security Settings > Advanced Audit Policy

$processsuspectes = @(
    'powershell.exe', 'cmd.exe', 'wscript.exe', 'cscript.exe',
    'mshta.exe', 'rundll32.exe', 'regsvr32.exe', 'certutil.exe',
    'bitsadmin.exe', 'msiexec.exe', 'psexec.exe', 'wmic.exe'
)

$debut = (Get-Date).AddHours(-4)

Get-WinEvent -FilterHashtable @{
    LogName   = 'Security'
    Id        = 4688
    StartTime = $debut
} -ErrorAction SilentlyContinue | ForEach-Object {
    $msg = $_.Message
    foreach ($proc in $processsuspectes) {
        if ($msg -match [regex]::Escape($proc)) {
            # Extraire les infos
            $newProcess = if ($msg -match 'New Process Name:\s+(.+)\r') { $Matches[1].Trim() } else { '?' }
            $creator   = if ($msg -match 'Creator Process Name:\s+(.+)\r') { $Matches[1].Trim() } else { '?' }
            $user      = if ($msg -match 'Account Name:\s+(\S+)') { $Matches[1] } else { '?' }

            Write-Host "[$($_.TimeCreated.ToString('HH:mm:ss'))] $user : $creator → $newProcess"
            break
        }
    }
}
